mapper.select:
select l.ledger_id as ledgerId, l.change_type as changeType, l.source_type as sourceType, l.source_ref_id as sourceRefId, l.points_change as pointsChange, l.balance_after as balanceAfter, l.remark, l.create_time as createTime from jst_points_ledger l inner join jst_points_account a on a.account_id = l.account_id and a.del_flag = '0' where l.del_flag = '0' and a.owner_id = #{userId} and a.owner_type in ('user', 'student')
and l.change_type = #{changeType}
order by l.create_time desc, l.ledger_id desc
